"use strict";parserFactory.register("wanderinginn.com",()=>new WanderinginnParser);class WanderinginnParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("#table-of-contents a:not(.book-title-num, .volume-book-card)")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div#reader-content")}findChapterTitle(e){const t=e.querySelectorAll("h2.elementor-heading-title");for(const e of t)if("loading..."!==e.textContent.trim())return e;return null}extractTitleImpl(){return"The Wandering Inn"}extractAuthor(){return"pirateaba"}removeNextAndPreviousChapterHyperlinks(e,t){util.removeElements(t.querySelectorAll("a[href*='https://wanderinginn.com/']"))}preprocessRawDom(e){const t=this.findContent(e);if(t){for(const e of t.querySelectorAll(".mrsha-write"))e.setAttribute("style","font-style: italic;");for(const e of t.querySelectorAll("span[style*='color:']"))e.classList.add("ibooks-dark-theme-use-custom-text-color")}}}